package com.inventory.product.controller;
import org.springframework.data.domain.Page;
import org.springframework.http.*;
import org.springframework.web.bind.annotation.*;
import com.inventory.product.dto.CategoryDto;
import com.inventory.product.service.CategoryService;
import jakarta.validation.Valid;
@RestController @RequestMapping("/api/categories") public class CategoryController { private final CategoryService categoryService; public CategoryController(CategoryService categoryService){this.categoryService=categoryService;} @PostMapping public ResponseEntity<CategoryDto> save(@Valid @RequestBody CategoryDto dto){return new ResponseEntity<>(categoryService.saveCategory(dto),HttpStatus.CREATED);} @GetMapping public ResponseEntity<Page<CategoryDto>> all(@RequestParam(defaultValue="0")int page,@RequestParam(defaultValue="10")int size,@RequestParam(defaultValue="id")String sortBy,@RequestParam(defaultValue="asc")String sortDir){return ResponseEntity.ok(categoryService.getAllCategories(page,size,sortBy,sortDir));} @GetMapping("/{id}") public ResponseEntity<CategoryDto> byId(@PathVariable Long id){return ResponseEntity.ok(categoryService.getCategoryById(id));} @PutMapping("/{id}") public ResponseEntity<CategoryDto> update(@PathVariable Long id,@Valid @RequestBody CategoryDto dto){return ResponseEntity.ok(categoryService.updateCategory(id,dto));} @DeleteMapping("/{id}") public ResponseEntity<Void> delete(@PathVariable Long id){categoryService.deleteCategory(id);return ResponseEntity.noContent().build();} @GetMapping("/search") public ResponseEntity<Page<CategoryDto>> search(@RequestParam String name,@RequestParam(defaultValue="0")int page,@RequestParam(defaultValue="10")int size){return ResponseEntity.ok(categoryService.searchByName(name,page,size));} }
